import java.util.*;

public class Solution {
    public static long solve(long[][] edges, boolean[] online, long k) {
        int n = online.length;
        List<List<Pair<Long, Long>>> graph = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            graph.add(new ArrayList<>());
        }

        for (long[] edge : edges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            long cost = edge[2];
            if (online[u] && online[v]) {
                graph.get(u).add(new Pair<>(v, cost));
            }
        }

        long maxScore = -1;
        PriorityQueue<long[]> heap = new PriorityQueue<>((a, b) -> Long.compare(b[0], a[0]));
        heap.offer(new long[]{-Long.MAX_VALUE, 0, 0}); // (-min_edge, current_node, total_cost)
        boolean[] visited = new boolean[n];

        while (!heap.isEmpty()) {
            long[] current = heap.poll();
            long minEdge = -current[0];
            int node = (int) current[1];
            long totalCost = current[2];

            if (visited[node]) {
                continue;
            }
            visited[node] = true;

            if (node == n - 1) {
                maxScore = Math.max(maxScore, minEdge);
                continue;
            }

            for (Pair<Long, Long> neighbor : graph.get(node)) {
                int v = (int) neighbor.getKey();
                long cost = neighbor.getValue();
                long newTotalCost = totalCost + cost;
                if (newTotalCost <= k) {
                    long newMinEdge = Math.min(minEdge, cost);
                    heap.offer(new long[]{-newMinEdge, v, newTotalCost});
                }
            }
        }

        return maxScore;
    }

    static class Pair<T1, T2> {
        private T1 key;
        private T2 value;

        public Pair(T1 key, T2 value) {
            this.key = key;
            this.value = value;
        }

        public T1 getKey() {
            return key;
        }

        public T2 getValue() {
            return value;
        }
    }
}
